import { Component, OnInit, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterLink } from '@angular/router';
import { Venue } from '../../core/models';

/**
 * GatherUp venues list (organizer). Mock data in a signal<Venue[]>;
 * service_agent wires ApiService.listVenues()/deleteVenue().
 */
@Component({
  selector: 'app-venues-list',
  standalone: true,
  imports: [CommonModule, RouterLink],
  templateUrl: './venues-list.component.html',
  styleUrl: './venues-list.component.css',
})
export class VenuesListComponent implements OnInit {
  readonly loading = signal(false);
  readonly error = signal<string | null>(null);

  readonly venues = signal<Venue[]>([
    { id: 'v1', name: 'The Warehouse', address: '12 Dock Road, Riverside', defaultCapacity: 150 },
    { id: 'v2', name: 'Riverside Hall', address: '5 Canal Street, Old Town', defaultCapacity: 80 },
    { id: 'v3', name: 'Rooftop 22', address: '22 Skyline Ave', defaultCapacity: 60 },
  ]);

  ngOnInit(): void {
    // service_agent: this.api.listVenues().subscribe(v => this.venues.set(v));
  }

  remove(v: Venue): void {
    this.venues.update((list) => list.filter((x) => x.id !== v.id));
    // service_agent: this.api.deleteVenue(v.id).subscribe(...)
  }
}
